{"nbformat":4,"nbformat_minor":0,"metadata":{"colab":{"provenance":[],"authorship_tag":"ABX9TyMThB0UBKxXeJHtXgkLT4XI"},"kernelspec":{"name":"python3","display_name":"Python 3"},"language_info":{"name":"python"}},"cells":[{"cell_type":"code","execution_count":1,"metadata":{"colab":{"base_uri":"https://localhost:8080/"},"id":"hhsEfOE1vFFB","executionInfo":{"status":"ok","timestamp":1779270048378,"user_tz":-420,"elapsed":72,"user":{"displayName":"Salomo Agus Purba","userId":"04376998070144597704"}},"outputId":"50403354-1f58-4472-edcf-5b89dc45a003"},"outputs":[{"output_type":"stream","name":"stdout","text":["Writing app.py\n"]}],"source":["%%writefile app.py\n","\n","import streamlit as st\n","import os\n","\n","from qdrant_client import QdrantClient\n","\n","from langchain_openai import ChatOpenAI\n","from langchain_openai import OpenAIEmbeddings\n","\n","from langchain_community.callbacks.manager import get_openai_callback\n","\n","from langchain.tools import tool\n","\n","from langgraph.graph import StateGraph\n","\n","\n","# =========================\n","# PAGE CONFIG\n","# =========================\n","\n","st.set_page_config(\n","    page_title=\"AI Talent Intelligence System\",\n","    page_icon=\"🧠\",\n","    layout=\"wide\"\n",")\n","\n","st.title(\"🧠 AI Talent Intelligence System\")\n","\n","\n","# =========================\n","# SESSION STATE\n","# =========================\n","\n","if \"chat_history\" not in st.session_state:\n","    st.session_state.chat_history = []\n","\n","\n","# =========================\n","# OPENAI & QDRANT\n","# =========================\n","\n","embedding_model = OpenAIEmbeddings(\n","    model=\"text-embedding-3-large\"\n",")\n","\n","llm = ChatOpenAI(\n","    model=\"gpt-4o-mini\",\n","    temperature=0\n",")\n","\n","client_qdrant = QdrantClient(\n","    url=st.secrets[\"QDRANT_URL\"],\n","    api_key=st.secrets[\"QDRANT_API_KEY\"]\n",")\n","\n","\n","# =========================\n","# RAG TOOL\n","# =========================\n","\n","@tool\n","def get_relevant_docs(question: str):\n","\n","    query_vector = embedding_model.embed_query(question)\n","\n","    results = client_qdrant.search(\n","        collection_name=\"resumes\",\n","        query_vector=query_vector,\n","        limit=5\n","    )\n","\n","    return results\n","\n","\n","# =========================\n","# QUERY REWRITE\n","# =========================\n","\n","def rewrite_query(query, history):\n","\n","    prompt = f\"\"\"\n","    Chat History:\n","    {history}\n","\n","    User Question:\n","    {query}\n","\n","    Rewrite into professional HR query.\n","    \"\"\"\n","\n","    response = llm.invoke(prompt)\n","\n","    return response.content\n","\n","\n","# =========================\n","# AGENTS\n","# =========================\n","\n","def retrieval_agent(state):\n","\n","    query = state[\"query\"]\n","    history = state[\"history\"]\n","\n","    rewritten_query = rewrite_query(query, history)\n","\n","    docs = get_relevant_docs.invoke(rewritten_query)\n","\n","    state[\"documents\"] = docs\n","    state[\"rewritten_query\"] = rewritten_query\n","\n","    return state\n","\n","\n","def analyzer_agent(state):\n","\n","    docs = state[\"documents\"]\n","\n","    prompt = f\"\"\"\n","    Analyze these resumes.\n","\n","    Documents:\n","    {docs}\n","\n","    Return:\n","    - Candidate Summary\n","    - Skills\n","    - Experience\n","    \"\"\"\n","\n","    response = llm.invoke(prompt)\n","\n","    state[\"analysis\"] = response.content\n","\n","    return state\n","\n","\n","def ranking_agent(state):\n","\n","    analysis = state[\"analysis\"]\n","\n","    prompt = f\"\"\"\n","    Rank candidates.\n","\n","    {analysis}\n","    \"\"\"\n","\n","    response = llm.invoke(prompt)\n","\n","    state[\"final_answer\"] = response.content\n","\n","    return state\n","\n","\n","# =========================\n","# LANGGRAPH\n","# =========================\n","\n","workflow = StateGraph(dict)\n","\n","workflow.add_node(\"retrieve\", retrieval_agent)\n","workflow.add_node(\"analyze\", analyzer_agent)\n","workflow.add_node(\"rank\", ranking_agent)\n","\n","workflow.set_entry_point(\"retrieve\")\n","\n","workflow.add_edge(\"retrieve\", \"analyze\")\n","workflow.add_edge(\"analyze\", \"rank\")\n","\n","graph = workflow.compile()\n","\n","\n","# =========================\n","# CHAT UI\n","# =========================\n","\n","user_input = st.chat_input(\"Ask something about candidates...\")\n","\n","if user_input:\n","\n","    st.chat_message(\"user\").write(user_input)\n","\n","    history_text = \"\\n\".join([\n","        f\"User: {x['query']}\\nAI: {x['answer']}\"\n","        for x in st.session_state.chat_history[-3:]\n","    ])\n","\n","    with get_openai_callback() as cb:\n","\n","        result = graph.invoke({\n","            \"query\": user_input,\n","            \"history\": history_text\n","        })\n","\n","    answer = result[\"final_answer\"]\n","\n","    st.chat_message(\"assistant\").write(answer)\n","\n","    # =========================\n","    # SOURCE DOCUMENTS\n","    # =========================\n","\n","    with st.expander(\"📄 Source Documents\"):\n","\n","        for i, doc in enumerate(result[\"documents\"]):\n","\n","            st.write(f\"### Document {i+1}\")\n","            st.write(doc.payload[\"text\"][:500])\n","\n","\n","    # =========================\n","    # TOKEN USAGE\n","    # =========================\n","\n","    with st.expander(\"📈 Token Usage\"):\n","\n","        st.write(\"Prompt Tokens:\", cb.prompt_tokens)\n","        st.write(\"Completion Tokens:\", cb.completion_tokens)\n","        st.write(\"Total Tokens:\", cb.total_tokens)\n","\n","\n","    # =========================\n","    # SAVE HISTORY\n","    # =========================\n","\n","    st.session_state.chat_history.append({\n","        \"query\": user_input,\n","        \"answer\": answer\n","    })\n","\n","\n","# =========================\n","# HISTORY UI\n","# =========================\n","\n","with st.sidebar:\n","\n","    st.header(\"🕓 Chat History\")\n","\n","    for chat in reversed(st.session_state.chat_history[-5:]):\n","\n","        st.write(\"User:\", chat[\"query\"])\n","        st.write(\"AI:\", chat[\"answer\"])\n","        st.divider()"]}]}